declare const wx: any

const MINGCUTE_TTF_BASE64 = ''

export function loadMingcuteFont() {
  if (typeof wx === 'undefined' || !wx.loadFontFace) return
  try {
    wx.loadFontFace({
      family: 'MingCute',
      global: true,
      source: 'url("data:font/ttf;base64,' + MINGCUTE_TTF_BASE64 + '")',
      desc: { style: 'normal', weight: 'normal' },
      success: () => {},
      fail: (err: any) => { console.error('[font] load MingCute failed', err) },
    })
  } catch (err) {
    console.error('[font] load MingCute failed', err)
  }
}

